  1→package mcp
  2→
  3→import (
  4→	"context"
  5→	"fmt"
  6→	"log/slog"
  7→	"strings"
  8→
  9→	"github.com/google/uuid"
 10→	mcpgo "github.com/mark3labs/mcp-go/mcp"
 11→	"github.com/mark3labs/mcp-go/server"
 12→
 13→	"github.com/ketang/flotsam/api/internal/item"
 14→)
 15→
 16→const (
 17→	defaultSearchLimit     = 10
 18→	maxSearchLimit         = 50
 19→	defaultSearchThreshold = 0.3
 20→)
 21→
 22→// --- search tool ---
 23→
 24→func searchTool() mcpgo.Tool {
 25→	return mcpgo.NewTool("search",
 26→		mcpgo.WithDescription("Search your knowledge base. Returns matching items with titles, types, tags, and content snippets."),
 27→		mcpgo.WithString("query", mcpgo.Required(), mcpgo.Description("Search query text")),
 28→		mcpgo.WithNumber("limit", mcpgo.Description("Max results to return (1-50, default 10)")),
 29→		mcpgo.WithString("type", mcpgo.Description("Filter by item type"), mcpgo.Enum("bookmark", "text_note", "voice_note")),
 30→	)
 31→}
 32→
 33→func searchHandler(deps Deps) server.ToolHandlerFunc {
 34→	return func(ctx context.Context, req mcpgo.CallToolRequest) (*mcpgo.CallToolResult, error) {
 35→		claims, errResult := requireAuth(ctx)
 36→		if errResult != nil {
 37→			return errResult, nil
 38→		}
 39→
 40→		query := req.GetString("query", "")
 41→		if query == "" {
 42→			return mcpgo.NewToolResultError("query is required"), nil
 43→		}
 44→
 45→		limit := req.GetInt("limit", defaultSearchLimit)
 46→		if limit < 1 {
 47→			limit = 1
 48→		}
 49→		if limit > maxSearchLimit {
 50→			limit = maxSearchLimit
 51→		}
 52→
 53→		var filter *item.Filter
 54→		if t := req.GetString("type", ""); t != "" {
 55→			filter = &item.Filter{Types: []string{t}}
 56→		}
 57→
 58→		result, err := doSearch(ctx, deps, claims.UserID, query, filter, limit)
 59→		if err != nil {
 60→			return mcpgo.NewToolResultError(fmt.Sprintf("search failed: %v", err)), nil
 61→		}
 62→
 63→		return mcpgo.NewToolResultText(formatSearchResults(result)), nil
 64→	}
 65→}
 66→
 67→// doSearch tries semantic search first, falling back to full-text search.
 68→func doSearch(ctx context.Context, deps Deps, ownerID uuid.UUID, query string, filter *item.Filter, limit int) (*item.SearchResult, error) {
 69→	if deps.Embedder != nil {
 70→		embedding, err := deps.Embedder.Embed(ctx, query)
 71→		if err != nil {
 72→			slog.WarnContext(ctx, "mcp: embedding failed, falling back to FTS", "error", err)
 73→		} else {
 74→			result, err := deps.Items.SemanticSearch(ctx, ownerID, embedding, filter, limit, defaultSearchThreshold)
 75→			if err == nil && len(result.Items) > 0 {
 76→				return result, nil
 77→			}
 78→			if err != nil {
 79→				slog.WarnContext(ctx, "mcp: semantic search failed, falling back to FTS", "error", err)
 80→			}
 81→		}
 82→	}
 83→
 84→	return deps.Items.Search(ctx, ownerID, query, filter, limit, 0)
 85→}
 86→
 87→// --- browse tool ---
 88→
 89→func browseTool() mcpgo.Tool {
 90→	return mcpgo.NewTool("browse",
 91→		mcpgo.WithDescription("Get the full content of an item by its ID."),
 92→		mcpgo.WithString("id", mcpgo.Required(), mcpgo.Description("Item UUID")),
 93→	)
 94→}
 95→
 96→func browseHandler(deps Deps) server.ToolHandlerFunc {
 97→	return func(ctx context.Context, req mcpgo.CallToolRequest) (*mcpgo.CallToolResult, error) {
 98→		claims, errResult := requireAuth(ctx)
 99→		if errResult != nil {
100→			return errResult, nil
101→		}
102→
103→		idStr := req.GetString("id", "")
104→		id, err := uuid.Parse(idStr)
105→		if err != nil {
106→			return mcpgo.NewToolResultError("invalid item ID: must be a valid UUID"), nil
107→		}
108→
109→		it, err := deps.Items.GetByID(ctx, claims.UserID, id)
110→		if err != nil {
111→			return mcpgo.NewToolResultError(fmt.Sprintf("failed to get item: %v", err)), nil
112→		}
113→
114→		return mcpgo.NewToolResultText(formatItem(it)), nil
115→	}
116→}
117→
118→// --- capture tool ---
119→
120→func captureTool() mcpgo.Tool {
121→	return mcpgo.NewTool("capture",
122→		mcpgo.WithDescription("Capture a new item into your knowledge base. Provide 'url' for a bookmark or 'content' for a note."),
123→		mcpgo.WithString("url", mcpgo.Description("URL to bookmark")),
124→		mcpgo.WithString("content", mcpgo.Description("Text content for a note")),
125→		mcpgo.WithString("title", mcpgo.Description("Optional title")),
126→		mcpgo.WithString("tags", mcpgo.Description("Comma-separated tags")),
127→		mcpgo.WithString("sensitivity", mcpgo.Description("Sensitivity level"), mcpgo.Enum("normal", "sensitive")),
128→	)
129→}
130→
131→func captureHandler(deps Deps) server.ToolHandlerFunc {
132→	return func(ctx context.Context, req mcpgo.CallToolRequest) (*mcpgo.CallToolResult, error) {
133→		claims, errResult := requireAuth(ctx)
134→		if errResult != nil {
135→			return errResult, nil
136→		}
137→
138→		url := req.GetString("url", "")
139→		content := req.GetString("content", "")
140→		titleStr := req.GetString("title", "")
141→		tagsStr := req.GetString("tags", "")
142→		sensitivity := req.GetString("sensitivity", "normal")
143→
144→		var title *string
145→		if titleStr != "" {
146→			title = &titleStr
147→		}
148→
149→		var tags []string
150→		if tagsStr != "" {
151→			for _, t := range strings.Split(tagsStr, ",") {
152→				t = strings.TrimSpace(t)
153→				if t != "" {
154→					tags = append(tags, t)
155→				}
156→			}
157→		}
158→
159→		switch {
160→		case url != "":
161→			it, err := deps.Items.CaptureBookmark(ctx, claims.UserID, item.BookmarkInput{
162→				URL:         url,
163→				Title:       title,
164→				Tags:        tags,
165→				Sensitivity: sensitivity,
166→				Source:      "mcp",
167→			})
168→			if err != nil {
169→				return mcpgo.NewToolResultError(fmt.Sprintf("failed to capture bookmark: %v", err)), nil
170→			}
171→			return mcpgo.NewToolResultText(formatItem(it)), nil
172→
173→		case content != "":
174→			it, err := deps.Items.CaptureNote(ctx, claims.UserID, item.NoteInput{
175→				Title:       title,
176→				Content:     content,
177→				Tags:        tags,
178→				Sensitivity: sensitivity,
179→				Source:      "mcp",
180→			})
181→			if err != nil {
182→				return mcpgo.NewToolResultError(fmt.Sprintf("failed to capture note: %v", err)), nil
183→			}
184→			return mcpgo.NewToolResultText(formatItem(it)), nil
185→
186→		default:
187→			return mcpgo.NewToolResultError("either 'url' (for bookmark) or 'content' (for note) is required"), nil
188→		}
189→	}
190→}
