 1→package mcp
 2→
 3→import (
 4→	"fmt"
 5→	"strings"
 6→
 7→	"github.com/ketang/flotsam/api/internal/item"
 8→)
 9→
10→const maxSnippetLen = 500
11→
12→// formatSearchResults renders a search result set as markdown text.
13→func formatSearchResults(result *item.SearchResult) string {
14→	if len(result.Items) == 0 {
15→		return "No items found."
16→	}
17→
18→	var b strings.Builder
19→	fmt.Fprintf(&b, "Found %d item(s):\n\n", result.Total)
20→
21→	for _, it := range result.Items {
22→		b.WriteString(formatItemSummary(it))
23→		b.WriteString("\n")
24→	}
25→
26→	if result.HasMore {
27→		b.WriteString("_(more results available — increase limit or refine query)_\n")
28→	}
29→
30→	return b.String()
31→}
32→
33→// formatItemSummary renders a single item as a compact summary line.
34→func formatItemSummary(it *item.Item) string {
35→	var b strings.Builder
36→
37→	title := it.ID.String()
38→	if it.Title != nil && *it.Title != "" {
39→		title = *it.Title
40→	}
41→
42→	fmt.Fprintf(&b, "- **%s** [%s] (id: %s)", title, it.Type, it.ID)
43→
44→	if len(it.Tags) > 0 {
45→		fmt.Fprintf(&b, " tags: %s", strings.Join(it.Tags, ", "))
46→	}
47→
48→	if it.ContentText != nil && *it.ContentText != "" {
49→		snippet := *it.ContentText
50→		if len(snippet) > maxSnippetLen {
51→			snippet = snippet[:maxSnippetLen] + "..."
52→		}
53→		fmt.Fprintf(&b, "\n  > %s", strings.ReplaceAll(snippet, "\n", "\n  > "))
54→	}
55→
56→	b.WriteString("\n")
57→	return b.String()
58→}
59→
60→// formatItem renders a full item as detailed markdown.
61→func formatItem(it *item.Item) string {
62→	var b strings.Builder
63→
64→	title := it.ID.String()
65→	if it.Title != nil && *it.Title != "" {
66→		title = *it.Title
67→	}
68→
69→	fmt.Fprintf(&b, "# %s\n\n", title)
70→	fmt.Fprintf(&b, "- **ID:** %s\n", it.ID)
71→	fmt.Fprintf(&b, "- **Type:** %s\n", it.Type)
72→	fmt.Fprintf(&b, "- **Status:** %s\n", it.Status)
73→	fmt.Fprintf(&b, "- **Sensitivity:** %s\n", it.Sensitivity)
74→	fmt.Fprintf(&b, "- **Source:** %s\n", it.Source)
75→	fmt.Fprintf(&b, "- **Captured:** %s\n", it.CapturedAt.Format("2006-01-02 15:04:05"))
76→
77→	if len(it.Tags) > 0 {
78→		fmt.Fprintf(&b, "- **Tags:** %s\n", strings.Join(it.Tags, ", "))
79→	}
80→
81→	if it.SourceURL != nil && *it.SourceURL != "" {
82→		fmt.Fprintf(&b, "- **URL:** %s\n", *it.SourceURL)
83→	}
84→
85→	if it.ContentURL != nil && *it.ContentURL != "" {
86→		fmt.Fprintf(&b, "- **Content URL:** %s\n", *it.ContentURL)
87→	}
88→
89→	if it.ContentText != nil && *it.ContentText != "" {
90→		fmt.Fprintf(&b, "\n## Content\n\n%s\n", *it.ContentText)
91→	}
92→
93→	return b.String()
94→}
