104→func TestSearchHandler_SemanticSearch(t *testing.T) {
105→	it := testItem()
106→	deps := Deps{
107→		Items: &mockItemSearcher{
108→			semanticSearchFn: func(_ context.Context, _ uuid.UUID, _ []float32, _ *item.Filter, _ int, _ float64) (*item.SearchResult, error) {
109→				return searchResult(it), nil
110→			},
111→		},
112→		Embedder: &mockEmbedder{
113→			embedFn: func(_ context.Context, _ string) ([]float32, error) {
114→				return []float32{0.1, 0.2}, nil
115→			},
116→			dims: 2,
117→		},
118→	}
119→
120→	handler := searchHandler(deps)
121→	req := makeCallToolRequest("search", map[string]any{"query": "test query"})
122→	result, err := handler(authedCtx(), req)
123→
124→	if err != nil {
125→		t.Fatalf("unexpected error: %v", err)
126→	}
127→	if result.IsError {
128→		t.Fatal("expected success result")
129→	}
130→	assertResultContains(t, result, "Test Item")
131→}
