-- +goose Up
-- +goose StatementBegin

-- Extensions
CREATE EXTENSION IF NOT EXISTS vector;
CREATE EXTENSION IF NOT EXISTS pg_trgm;

-- Enum types
CREATE TYPE item_type AS ENUM (
    'bookmark', 'voice_note', 'text_note', 'drive_doc', 'highlight', 'file'
);

CREATE TYPE item_status AS ENUM (
    'pending', 'processing', 'ready', 'error'
);

CREATE TYPE sensitivity_level AS ENUM (
    'public', 'normal', 'sensitive', 'private'
);

-- Users
CREATE TABLE users (
    id            UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    email         TEXT UNIQUE NOT NULL,
    display_name  TEXT,
    password_hash TEXT,
    auth_provider TEXT DEFAULT 'local',
    auth_subject  TEXT,
    settings      JSONB NOT NULL DEFAULT '{}',
    created_at    TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_at    TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Items (unified content table)
CREATE TABLE items (
    id            UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    owner_id      UUID NOT NULL REFERENCES users(id),
    type          item_type NOT NULL,
    status        item_status NOT NULL DEFAULT 'pending',
    sensitivity   sensitivity_level NOT NULL DEFAULT 'normal',
    title         TEXT,
    content_text  TEXT,
    content_url   TEXT,
    embedding     vector(1536),
    search_vector tsvector GENERATED ALWAYS AS (
        setweight(to_tsvector('english', coalesce(title, '')), 'A') ||
        setweight(to_tsvector('english', coalesce(content_text, '')), 'B')
    ) STORED,
    tags          TEXT[] DEFAULT '{}',
    metadata      JSONB NOT NULL DEFAULT '{}',
    auto_metadata JSONB NOT NULL DEFAULT '{}',
    source        TEXT NOT NULL,
    source_url    TEXT,
    created_at    TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_at    TIMESTAMPTZ NOT NULL DEFAULT now(),
    captured_at   TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Items indexes
CREATE INDEX idx_items_owner ON items(owner_id);
CREATE INDEX idx_items_type ON items(owner_id, type);
CREATE INDEX idx_items_created ON items(owner_id, created_at DESC);
CREATE INDEX idx_items_tags ON items USING GIN(tags);
CREATE INDEX idx_items_metadata ON items USING GIN(metadata);
CREATE INDEX idx_items_search ON items USING GIN(search_vector);
CREATE INDEX idx_items_embedding ON items USING ivfflat(embedding vector_cosine_ops) WITH (lists = 100);
CREATE INDEX idx_items_sensitivity ON items(owner_id, sensitivity);

-- MCP clients
CREATE TABLE mcp_clients (
    id                UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    owner_id          UUID NOT NULL REFERENCES users(id),
    name              TEXT NOT NULL,
    api_key_hash      TEXT NOT NULL,
    permissions       JSONB NOT NULL DEFAULT '{}',
    requires_approval TEXT[] DEFAULT '{}',
    active            BOOLEAN NOT NULL DEFAULT true,
    last_used_at      TIMESTAMPTZ,
    created_at        TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Audit log
CREATE TABLE audit_log (
    id               UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    user_id          UUID NOT NULL REFERENCES users(id),
    client_id        UUID REFERENCES mcp_clients(id),
    action           TEXT NOT NULL,
    resource_type    TEXT,
    resource_id      UUID,
    request          JSONB,
    response_summary JSONB,
    approved         BOOLEAN,
    created_at       TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Trigger function: auto-update updated_at
CREATE OR REPLACE FUNCTION set_updated_at()
RETURNS TRIGGER AS $$
BEGIN
    NEW.updated_at = now();
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_users_updated_at
    BEFORE UPDATE ON users
    FOR EACH ROW EXECUTE FUNCTION set_updated_at();

CREATE TRIGGER trg_items_updated_at
    BEFORE UPDATE ON items
    FOR EACH ROW EXECUTE FUNCTION set_updated_at();

-- +goose StatementEnd

-- +goose Down
-- +goose StatementBegin

DROP TRIGGER IF EXISTS trg_items_updated_at ON items;
DROP TRIGGER IF EXISTS trg_users_updated_at ON users;
DROP FUNCTION IF EXISTS set_updated_at();

DROP TABLE IF EXISTS audit_log;
DROP TABLE IF EXISTS mcp_clients;
DROP TABLE IF EXISTS items;
DROP TABLE IF EXISTS users;

DROP TYPE IF EXISTS sensitivity_level;
DROP TYPE IF EXISTS item_status;
DROP TYPE IF EXISTS item_type;

DROP EXTENSION IF EXISTS pg_trgm;
DROP EXTENSION IF EXISTS vector;

-- +goose StatementEnd

package mcp

import (
	"context"

	"github.com/google/uuid"

	"github.com/ketang/flotsam/api/internal/item"
)

// ItemSearcher abstracts the item.Service methods the MCP server needs.
type ItemSearcher interface {
	GetByID(ctx context.Context, ownerID, itemID uuid.UUID) (*item.Item, error)
	Search(ctx context.Context, ownerID uuid.UUID, query string, filter *item.Filter, limit int, threshold float64) (*item.SearchResult, error)
	SemanticSearch(ctx context.Context, ownerID uuid.UUID, embedding []float32, filter *item.Filter, limit int, threshold float64) (*item.SearchResult, error)
	CaptureBookmark(ctx context.Context, ownerID uuid.UUID, input item.BookmarkInput) (*item.Item, error)
	CaptureNote(ctx context.Context, ownerID uuid.UUID, input item.NoteInput) (*item.Item, error)
}

// Embedder generates vector embeddings for search queries.
type Embedder interface {
	Embed(ctx context.Context, text string) ([]float32, error)
	Dimensions() int
}

// Deps holds MCP server dependencies.
type Deps struct {
	Items    ItemSearcher
	Embedder Embedder // nil if embedding not configured
}

package mcp

import (
	"context"
	"net/http"

	mcpgo "github.com/mark3labs/mcp-go/mcp"
	"github.com/mark3labs/mcp-go/server"

	"github.com/ketang/flotsam/api/internal/auth"
	"github.com/ketang/flotsam/api/internal/version"
)

// NewHandler creates an MCP HTTP handler with search, browse, and capture tools.
func NewHandler(deps Deps) http.Handler {
	s := server.NewMCPServer(
		"flotsam",
		version.Version,
		server.WithToolCapabilities(false),
	)

	s.AddTool(searchTool(), searchHandler(deps))
	s.AddTool(browseTool(), browseHandler(deps))
	s.AddTool(captureTool(), captureHandler(deps))

	httpServer := server.NewStreamableHTTPServer(s,
		server.WithStateLess(true),
		server.WithHTTPContextFunc(func(ctx context.Context, r *http.Request) context.Context {
			if claims := auth.GetClaims(r.Context()); claims != nil {
				ctx = auth.WithClaims(ctx, claims)
			}
			return ctx
		}),
	)

	return httpServer
}

// requireAuth extracts claims from context, returning an error result if unauthenticated.
func requireAuth(ctx context.Context) (*auth.Claims, *mcpgo.CallToolResult) {
	claims := auth.GetClaims(ctx)
	if claims == nil {
		return nil, mcpgo.NewToolResultError("authentication required")
	}
	return claims, nil
}

