package auth

import (
	"errors"
	"fmt"

	"github.com/golang-jwt/jwt/v5"
	"github.com/google/uuid"
)

// Claims extends jwt.RegisteredClaims with application-specific fields.
type Claims struct {
	jwt.RegisteredClaims
	UserID     uuid.UUID `json:"uid"`
	Email      string    `json:"email,omitempty"`
	ClientType string    `json:"ctype,omitempty"` // web|cli|mobile
}

// Validator validates a JWT token string and returns parsed claims.
type Validator interface {
	Validate(tokenString string) (*Claims, error)
}

// HMACValidator validates HS256 tokens using a shared secret.
type HMACValidator struct {
	secret []byte
}

// NewHMACValidator creates a Validator using HS256 with the provided secret.
func NewHMACValidator(secret string) *HMACValidator {
	return &HMACValidator{secret: []byte(secret)}
}

// Validate parses and validates an HS256 JWT token string.
func (v *HMACValidator) Validate(tokenString string) (*Claims, error) {
	claims := &Claims{}
	token, err := jwt.ParseWithClaims(tokenString, claims, func(t *jwt.Token) (any, error) {
		if _, ok := t.Method.(*jwt.SigningMethodHMAC); !ok {
			return nil, fmt.Errorf("auth: unexpected signing method: %v", t.Header["alg"])
		}
		return v.secret, nil
	})
	if err != nil {
		return nil, fmt.Errorf("auth: token validation failed: %w", err)
	}
	if !token.Valid {
		return nil, errors.New("auth: token is not valid")
	}
	return claims, nil
}

package auth

import "context"

type contextKey struct{}

// WithClaims stores JWT claims in the context.
func WithClaims(ctx context.Context, claims *Claims) context.Context {
	return context.WithValue(ctx, contextKey{}, claims)
}

// GetClaims retrieves JWT claims from the context. Returns nil if not present.
func GetClaims(ctx context.Context) *Claims {
	claims, _ := ctx.Value(contextKey{}).(*Claims)
	return claims
}

package router

import (
	"encoding/json"
	"log/slog"
	"net/http"
	"strings"

	"github.com/99designs/gqlgen/graphql/handler"
	"github.com/99designs/gqlgen/graphql/handler/extension"
	"github.com/99designs/gqlgen/graphql/handler/transport"
	"github.com/99designs/gqlgen/graphql/playground"
	"github.com/go-chi/chi/v5"
	chimiddleware "github.com/go-chi/chi/v5/middleware"
	"github.com/go-chi/cors"
	"github.com/jackc/pgx/v5"
	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/riverqueue/river"

	"github.com/ketang/flotsam/api/graph/generated"
	"github.com/ketang/flotsam/api/graph/resolver"
	"github.com/ketang/flotsam/api/internal/auth"
	"github.com/ketang/flotsam/api/internal/config"
	"github.com/ketang/flotsam/api/internal/item"
	flotsammcp "github.com/ketang/flotsam/api/internal/mcp"
	flotsammiddleware "github.com/ketang/flotsam/api/internal/middleware"
	"github.com/ketang/flotsam/api/internal/provider"
	"github.com/ketang/flotsam/api/internal/storage"
	"github.com/ketang/flotsam/api/internal/user"
	"github.com/ketang/flotsam/api/internal/version"
)

// Deps holds the dependencies needed to construct the router.
type Deps struct {
	Config      *config.Config
	Pool        *pgxpool.Pool
	Validator   auth.Validator
	Storage     *storage.Client // nil if S3 not configured
	RiverClient *river.Client[pgx.Tx]
	Items       *item.Service
	Users       *user.Service
	Issuer      *auth.Issuer
	Embedder    provider.Embedder // nil if no embedding provider configured
}

// New constructs the chi router with all middleware, routes, and handlers.
func New(deps Deps) http.Handler {
	r := chi.NewRouter()

	// Global middleware (applied to every request)
	r.Use(flotsammiddleware.RequestID)
	r.Use(flotsammiddleware.Logging)
	r.Use(flotsammiddleware.Recovery)
	r.Use(chimiddleware.RealIP)
	r.Use(chimiddleware.StripSlashes)

	// CORS (if configured)
	if deps.Config.CORSOrigins != "" {
		origins := parseCORSOrigins(deps.Config.CORSOrigins)
		r.Use(cors.Handler(cors.Options{
			AllowedOrigins:   origins,
			AllowedMethods:   []string{"GET", "POST", "PUT", "DELETE", "OPTIONS"},
			AllowedHeaders:   []string{"Accept", "Authorization", "Content-Type"},
			AllowCredentials: true,
			MaxAge:           300,
		}))
	}

	// Health endpoint — no auth
	r.Get("/health", healthHandler)

	// GraphQL handler
	gqlSrv := handler.New(generated.NewExecutableSchema(generated.Config{
		Resolvers: &resolver.Resolver{
			ItemService: deps.Items,
			UserService: deps.Users,
			Issuer:      deps.Issuer,
			RiverClient: deps.RiverClient,
			Storage:     deps.Storage,
			Embedder:    deps.Embedder,
		},
	}))
	gqlSrv.AddTransport(transport.POST{})
	gqlSrv.AddTransport(transport.GET{})
	if deps.Config.GQLIntrospection {
		gqlSrv.Use(extension.Introspection{})
	}

	// GraphQL endpoint — optional auth + rate limit
	r.Route("/graphql", func(r chi.Router) {
		r.Use(flotsammiddleware.OptionalAuth(deps.Validator))
		if deps.Config.RateLimitEnabled {
			rl := flotsammiddleware.NewRateLimiter(deps.Config.RateLimitGraphQL)
			r.Use(rl.Limit)
		}
		r.Post("/", gqlSrv.ServeHTTP)
		r.Get("/", gqlSrv.ServeHTTP)
	})

	// GraphQL playground (dev only)
	if deps.Config.GQLPlayground {
		r.Get("/playground", playground.Handler("Flotsam API", "/graphql"))
		slog.Info("router: GraphQL playground enabled at /playground")
	}

	// MCP endpoint — mandatory auth + rate limit
	if deps.Config.MCPEnabled {
		r.Route("/mcp", func(r chi.Router) {
			r.Use(flotsammiddleware.Auth(deps.Validator))
			if deps.Config.RateLimitEnabled {
				rl := flotsammiddleware.NewRateLimiter(deps.Config.RateLimitMCP)
				r.Use(rl.Limit)
			}
			mcpHandler := flotsammcp.NewHandler(flotsammcp.Deps{
			Items:    deps.Items,
			Embedder: deps.Embedder,
		})
		r.Handle("/*", mcpHandler)
		})
		slog.Info("router: MCP endpoint enabled at /mcp")
	}

	// Upload endpoint — mandatory auth
	r.Route("/upload", func(r chi.Router) {
		r.Use(flotsammiddleware.Auth(deps.Validator))
		r.Post("/", uploadHandler(deps.Storage, deps.Config.MaxUploadSize))
	})

	slog.Info("router: initialized",
		"cors_origins", deps.Config.CORSOrigins,
		"mcp_enabled", deps.Config.MCPEnabled,
		"rate_limit_enabled", deps.Config.RateLimitEnabled,
	)

	return r
}

func healthHandler(w http.ResponseWriter, _ *http.Request) {
	w.Header().Set("Content-Type", "application/json")
	_ = json.NewEncoder(w).Encode(map[string]string{
		"status":  "ok",
		"version": version.Version,
	})
}

func parseCORSOrigins(s string) []string {
	parts := strings.Split(s, ",")
	origins := make([]string, 0, len(parts))
	for _, p := range parts {
		p = strings.TrimSpace(p)
		if p != "" {
			origins = append(origins, p)
		}
	}
	return origins
}

package middleware

import (
	"log/slog"
	"net/http"
	"strings"

	"github.com/ketang/flotsam/api/internal/auth"
)

// Auth validates the Bearer JWT token from the Authorization header.
// On success, claims are stored in the request context via auth.WithClaims.
// On failure, responds with 401 Unauthorized.
func Auth(validator auth.Validator) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			token, ok := bearerToken(r)
			if !ok {
				slog.WarnContext(r.Context(), "auth: missing or malformed authorization header",
					"request_id", requestIDFromContext(r.Context()),
					"method", r.Method,
					"path", r.URL.Path,
					"remote_addr", r.RemoteAddr,
				)
				w.Header().Set("WWW-Authenticate", `Bearer realm="flotsam"`)
				http.Error(w, "missing or malformed authorization header", http.StatusUnauthorized)
				return
			}

			claims, err := validator.Validate(token)
			if err != nil {
				slog.WarnContext(r.Context(), "auth: invalid or expired token",
					"request_id", requestIDFromContext(r.Context()),
					"method", r.Method,
					"path", r.URL.Path,
					"remote_addr", r.RemoteAddr,
					"error", err,
				)
				w.Header().Set("WWW-Authenticate", `Bearer realm="flotsam", error="invalid_token"`)
				http.Error(w, "invalid or expired token", http.StatusUnauthorized)
				return
			}

			ctx := auth.WithClaims(r.Context(), claims)
			next.ServeHTTP(w, r.WithContext(ctx))
		})
	}
}

// OptionalAuth validates a Bearer token if present but allows unauthenticated requests.
// If a token is present and valid, claims are stored in context.
// If a token is present but invalid, responds with 401.
// If no token is present, the request proceeds without claims.
func OptionalAuth(validator auth.Validator) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			token, ok := bearerToken(r)
			if !ok {
				next.ServeHTTP(w, r)
				return
			}

			claims, err := validator.Validate(token)
			if err != nil {
				slog.WarnContext(r.Context(), "auth: invalid or expired token",
					"request_id", requestIDFromContext(r.Context()),
					"method", r.Method,
					"path", r.URL.Path,
					"remote_addr", r.RemoteAddr,
					"error", err,
				)
				w.Header().Set("WWW-Authenticate", `Bearer realm="flotsam", error="invalid_token"`)
				http.Error(w, "invalid or expired token", http.StatusUnauthorized)
				return
			}

			ctx := auth.WithClaims(r.Context(), claims)
			next.ServeHTTP(w, r.WithContext(ctx))
		})
	}
}

// bearerToken extracts the token from "Authorization: Bearer <token>".
func bearerToken(r *http.Request) (string, bool) {
	header := r.Header.Get("Authorization")
	if header == "" {
		return "", false
	}
	parts := strings.SplitN(header, " ", 2)
	if len(parts) != 2 || !strings.EqualFold(parts[0], "bearer") {
		return "", false
	}
	token := strings.TrimSpace(parts[1])
	if token == "" {
		return "", false
	}
	return token, true
}

