package mcpclient

import (
	"strings"
	"testing"
)

func TestGenerateAPIKey(t *testing.T) {
	plain, hash, err := generateAPIKey()
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	if !strings.HasPrefix(plain, apiKeyPrefix) {
		t.Errorf("expected key to start with %q, got %q", apiKeyPrefix, plain[:10])
	}

	// Key should be long enough: prefix (4) + base64url(32 bytes) = ~48 chars
	if len(plain) < 40 {
		t.Errorf("key too short: %d chars", len(plain))
	}

	// Hash should be hex-encoded SHA-256 (64 chars)
	if len(hash) != 64 {
		t.Errorf("expected 64-char hex hash, got %d chars", len(hash))
	}

	// HashAPIKey should produce same result
	if got := HashAPIKey(plain); got != hash {
		t.Errorf("HashAPIKey mismatch: %q != %q", got, hash)
	}
}

func TestGenerateAPIKey_Unique(t *testing.T) {
	plain1, _, _ := generateAPIKey()
	plain2, _, _ := generateAPIKey()
	if plain1 == plain2 {
		t.Error("two generated keys should not be identical")
	}
}

func TestHashAPIKey(t *testing.T) {
	// Deterministic: same input → same output
	hash1 := HashAPIKey("flt_test123")
	hash2 := HashAPIKey("flt_test123")
	if hash1 != hash2 {
		t.Error("same input should produce same hash")
	}

	// Different input → different output
	hash3 := HashAPIKey("flt_test456")
	if hash1 == hash3 {
		t.Error("different inputs should produce different hashes")
	}
}

func TestClientHasTool(t *testing.T) {
	c := &Client{
		Permissions: Permissions{
			Tools:          []string{"search", "browse"},
			MaxSensitivity: "normal",
		},
	}

	tests := []struct {
		tool     string
		expected bool
	}{
		{"search", true},
		{"browse", true},
		{"capture", false},
		{"", false},
	}

	for _, tt := range tests {
		t.Run(tt.tool, func(t *testing.T) {
			if got := c.HasTool(tt.tool); got != tt.expected {
				t.Errorf("HasTool(%q) = %v, want %v", tt.tool, got, tt.expected)
			}
		})
	}
}

func TestClientHasTool_EmptyPermissions(t *testing.T) {
	c := &Client{}
	if c.HasTool("search") {
		t.Error("empty permissions should deny all tools")
	}
}
